# Vantro: collapsible sidebar - downloads + runs internal patcher
$ErrorActionPreference = "Stop"

Write-Host "Writing internal patcher to C:\vantro\sidebar-internal.ps1..." -ForegroundColor Cyan
$b64 = ""
[System.IO.File]::WriteAllBytes("C:\vantro\sidebar-internal.ps1", [System.Convert]::FromBase64String($b64))

Write-Host "Running patcher..." -ForegroundColor Cyan
powershell -ExecutionPolicy Bypass -File "C:\vantro\sidebar-internal.ps1"

Write-Host ""
Write-Host "Done. Now run:" -ForegroundColor Yellow
Write-Host "  git add components/admin/AdminDashboard.tsx"
Write-Host "  git commit -m 'feat(ui): collapsible sidebar with persistence and mobile auto-collapse'"
Write-Host "  git push origin master"
